  FILTER(LANG(?label) = 'en')
}

SELECT DISTINCT ?label WHERE {
  ?court wdt:P17 wd:Q35 ; rdfs:label ?label .
  FILTER(LANG(?label) = 'en' && CONTAINS(STR(?label) , 'bankruptcy'))
}

SELECT ?birthYear WHERE {
  ?player wdt:P1344 wd:Q2070302 .
  ?player wdt:P569 ?birthDate .
  BIND(YEAR(?birthDate) AS ?birthYear)
  OPTIONAL {
    ?player wdt:P734 ?lastName
  }
}
ORDER BY ASC(?birthYear) ASC(?lastName)
LIMIT 6

SELECT(SUM(?games) AS ?total) WHERE {
  ?series wdt:P1350 ?games .
}

SELECT(MAX(?attendance) AS ?maxAttendance) WHERE {
  {
    wd:Q3511178 wdt:P1684 ?game .
    {
      ?game wdt:P1031 wd:Q180736
    } UNION {
      ?game wdt:P1032 wd:Q180736
    }
    .
    ?game wdt:P1873 ?attendance .
  } UNION {
    wd:Q14870260 wdt:P1684 ?game .
    {
      ?game wdt:P1031 wd:Q180736
    } UNION {
      ?game wdt:P1032 wd:Q180736
    }
    .
    ?game wdt:P1873 ?attendance .
  } UNION {
    wd:Q56692089 wdt:P1684 ?game .
    {
      ?game wdt:P1031 wd:Q180736
    } UNION {
      ?game wdt:P1032 wd:Q180736
    }
    .
    ?game wdt:P1873 ?attendance .
  }
}

SELECT(YEAR(?end_date) AS ?year) WHERE {
  wd:Q60823607 wdt:P582 ?end_date .
}

SELECT((?max2006 - ?min2011) AS ?difference) WHERE {
  {
    SELECT(MAX(?att) AS ?max2006) WHERE {
      ?game wdt:P361 wd:Q3511260 ; wdt:P10031 ?att .
    }
  }
  {
    SELECT(MIN(?att) AS ?min2011) WHERE {
      ?game wdt:P361 wd:Q1099083 ; wdt:P10031 ?att .
    }
  }
}

SELECT(MAX(?duration) AS ?max_duration) WHERE {
  VALUES ?series {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
  ?game wdt:P1548 ?series .
  {
    ?game wdt:P1095 wd:Q15083
  } UNION {
    ?game wdt:P1591 wd:Q15083
  }
  ?game wdt:P5204 ?duration .
}

SELECT(MAX(?races) - MIN(?races) AS ?difference) WHERE {
  ?season wdt:P139 wd:Q175891 ; wdt:P139 wd:Q5988 ; wdt:P2255 ?races .
}

SELECT((?coll_span - ?rich_span) AS ?difference) WHERE {
  {
    SELECT(MAX(?coll_year) AS ?coll_max)(MIN(?coll_year) AS ?coll_min) WHERE {
      wd:Q249679 wdt:P3450 ?season .
      ?season wdt:P585 ?coll_year .
    }
  }
  {
    SELECT(MAX(?rich_year) AS ?rich_max)(MIN(?rich_year) AS ?rich_min) WHERE {
      wd:Q2521385 wdt:P3450 ?season .
      ?season wdt:P585 ?rich_year .
    }
  }
  BIND(?coll_max - ?coll_min AS ?coll_span)
  BIND(?rich_max - ?rich_min AS ?rich_span)
}

SELECT ?medal WHERE {
  wd:Q3809714 wdt:P106 wd:Q937857 .
}

SELECT(MAX(?attendance) AS ?max_attendance) WHERE {
  VALUES ?series {
    wd:Q3511178 wd:Q14870260 wd:Q56692089
  }
  ?series wdt:P1790 ?game .
  ?game wdt:P1072 ?attendance .
}

SELECT ?entity WHERE {
  wd:Q451002 wdt:P106 ?occupation .
}

SELECT(SUBSTR(STR(?inception) , 1 , 4) AS ?year) WHERE {
  wd:Q610865 wdt:P571 ?inception .
}

SELECT(MAX(?year) AS ?maxYear) WHERE {
  ?series wdt:P31 wd:Q265538 ;(wdt:P121 | wdt:P122) wd:Q334634 ; wdt:P585 ?year .
}
ORDER BY DESC(?year)
LIMIT 1

SELECT(YEAR(?inception) AS ?year) WHERE {
  wd:Q109441514 wdt:P571 ?inception
}

SELECT ?test WHERE {
  wd:Q985351 rdfs:label ?label
  FILTER(LANG(?label) = 'en')
}

SELECT(MAX(?attendance) AS ?maxAttendance) WHERE {
  ?series wdt:P31 wd:Q530605 ; wdt:P585 ?eventDate ; wdt:P1231 wd:Q16611 ; wdt:P1231 wd:Q17043 .
  FILTER(STR(?eventDate) >= "1970-01-01" && STR(?eventDate) < "1980-01-01")
  ?game wdt:P1222 ?series .
  ?game wdt:P1135 ?attendance .
}

SELECT ?book WHERE {
  wd:Q214371 wdt:P31 wd:Q7725634 ; wdt:P577 ?pubDate .
  FILTER(YEAR(?pubDate) = 1925)
}

SELECT(MIN(?numGames) AS ?minGames) WHERE {
  ?series wdt:P31 wd:Q549719 ; wd:P2869 wd:Q35172 ; wdt:P585 ?startYear ; wdt:P5948 ?numGames .
  FILTER(SUBSTR(STR(?startYear) , 1 , 4) IN("2004" , "2007" , "2013" , "2018"))
}

SELECT ?nickname WHERE {
  wd:Q164134 wdt:P1813 ?nickname
}

SELECT ?episodeLabel WHERE {
  wd:Q1133560 wdt:P527 ?episode .
  ?episode rdfs:label ?episodeLabel .
  FILTER(LANG(?episodeLabel) = "en" && STR(?episodeLabel) = "Mama's Baby, Carlton's Maybe")
}

SELECT ?albumLabel WHERE {
  wd:Q718759 rdfs:label ?albumLabel .
  FILTER(LANG(?albumLabel) = 'en')
}
